import { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { contentApi } from '../services/api';

export default function VideoDetail() {
  const { id } = useParams();
  const [video, setVideo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    contentApi
      .getById(id)
      .then(setVideo)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) return <div className="page-loading">Loading...</div>;
  if (error || !video) return <div className="page-error">{error || 'Video not found'}</div>;

  return (
    <div className="detail-page">
      <Link to="/videos" className="back-link">← Back to Videos</Link>
      <div className="detail-video-wrap">
        <video controls poster={video.thumbnail} className="detail-video">
          <source src={video.videoUrl} type="video/mp4" />
          Your browser does not support video playback.
        </video>
      </div>
      <div className="detail-meta">
        <div className="detail-badges">
          {video.featured && <span className="badge featured">Featured</span>}
          {video.trending && <span className="badge trending">Trending</span>}
        </div>
        <h1>{video.title}</h1>
        <p className="detail-desc">{video.description}</p>
        <time className="detail-date">
          {new Date(video.createdAt).toLocaleDateString('en-US', {
            weekday: 'long',
            month: 'long',
            day: 'numeric',
            year: 'numeric',
          })}
        </time>
      </div>
    </div>
  );
}
